mapper.update:
update jst_order_main
set order_status = #{targetStatus},
    update_by = #{updateBy},
    update_time = #{updateTime}

        , pay_time = #{payTime}

where order_id = #{orderId}
  and order_status = #{expectedStatus}
  and del_flag = '0'

mapper.select:
select om.order_id, om.order_no, om.contest_id, c.contest_name, om.participant_id, p.name as participant_name, om.list_amount, om.coupon_amount, om.points_deduct_amount, om.points_used, om.net_pay_amount, om.order_type, om.pay_method, om.order_status, om.pay_time, om.create_time from jst_order_main om left join jst_contest c on c.contest_id = om.contest_id and c.del_flag = '0' left join jst_participant p on p.participant_id = om.participant_id and p.del_flag = '0' where om.del_flag = '0' and om.user_id = #{userId}
and om.order_no = #{orderNo}
and om.order_status = #{orderStatus}
and om.pay_method = #{payMethod}
and om.contest_id = #{contestId}
order by om.create_time desc, om.order_id desc

select om.order_id, om.order_no, om.contest_id, c.contest_name, om.participant_id, p.name as participant_name, om.list_amount, om.coupon_amount, om.points_deduct_amount, om.points_used, om.net_pay_amount, om.order_type, om.pay_method, om.order_status, om.pay_time, om.create_time from jst_order_main om left join jst_contest c on c.contest_id = om.contest_id and c.del_flag = '0' left join jst_participant p on p.participant_id = om.participant_id and p.del_flag = '0' where om.del_flag = '0'
and om.order_no = #{orderNo}
and om.order_status = #{orderStatus}
and om.pay_method = #{payMethod}
and om.contest_id = #{contestId}
and om.user_id = #{userId}
and om.channel_id = #{channelId}
order by om.create_time desc, om.order_id desc
